var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"나래 양의 데이터만이라면 지금이라도 조정할 수 있을 걸세.","JPN":"ナルミ君のデータだけだったら、今からでも調整できるはずだ。","ENG":"It's not too late for us to change Narae's data.","TWN":"如果只是娜拉的資料，現在應該還能調整。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"신경 쓰인다면 바로 조치해 두지.","JPN":"気になるならすぐに変えるが。","ENG":"Let me know if it bothers you. I will make changes right away.","TWN":"你要是介意的話，我現在就能換成別的。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"괜찮아. 넣자고 한 건 나잖아.","JPN":"大丈夫。入れようと言ったのは私だし。","ENG":"It's all right. I'm the one who suggested it.","TWN":"沒關係，是我說要放進去的。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나이트와 비숍은 서로 정반대였어. 직접 겪어 보면 세 사람에게도 도움이 될 거야.","JPN":"ナイトとビショップは正反対だった。みんなも直接経験してみれば役に立つはずだよ。","ENG":"Knight and Bishop were polar opposites. It'll be useful for them to go through it.","TWN":"騎士和大主教的戰鬥風格正好相反。都體驗一遍的話，對她們三個也有幫助。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쳇, 아깝네. 조금만 더 빨리 반응했어도 반격 성공이었는데.","JPN":"チッ、もったいないな。もうちょっと早く反応してたら反撃成功だったのに。","ENG":"Tsk, such a close call. We would have succeeded in attacking back if we'd been faster.","TWN":"嘖，真可惜。反應速度再快一點的話，就可以反擊成功了。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아뇨. 방패는 이미 한계였어요. 이번 같은 방식으로는 어려울 것 같아요.","JPN":"いいえ。盾はすでに限界だったわ。今回みたいなやり方では難しいと思う。","ENG":"No, the shield was at its limit. I don't think this method will work a second time.","TWN":"不行，盾牌已經到達極限，這個戰術似乎行不通。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으, 그럼 반격을 해도 위험했겠네요.","JPN":"うう、それじゃあ反撃しても危険だったかもしれませんね。","ENG":"Nngh, that means it would've been dangerous to hit back.","TWN":"呃呃，那個反擊也很危險。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다시 한 번 도전해 봐요. 이번에는 더 잘할 수 있을 거예요.","JPN":"もう一度挑戦してみましょう。次はもっとうまくやれるはずです。","ENG":"Let's try again. We'll do better this time.","TWN":"再挑戰一次吧。這次我們一定能做得更好。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"응? 왜 그러세요?","JPN":"うん？　どうしましたか？","ENG":"Hm? What's wrong?","TWN":"嗯？怎麼了？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저기…… 나한테 화 안 났어?","JPN":"あの……私に怒ってないの？","ENG":"You, um... Aren't you angry at me?","TWN":"那個……你不生我的氣嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 제가 펠리세트한테요?","JPN":"はい？　私がフェリセットにですか？","ENG":"Huh? Me? Angry at you?","TWN":"嗯？我生你的氣？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……사과하려고, 했는데. 너랑. 스키너한테.","JPN":"……謝ろうと、思ったのに。あなたと。スキナーに。","ENG":"...I wanted to apologize. To you and Skinner.","TWN":"……我想跟你，還有史金納道歉。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으음, 물론 화내고 물건을 던질 때는 무섭긴 하지만…","JPN":"うーん、もちろん怒ったり物を投げたりする時は怖いですけど……","ENG":"Mmm, I will admit, you are pretty intimidating when you throw things and yell...","TWN":"嗯嗯，你發脾氣摔東西的時候我是有點害怕……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이해해요. 최선을 다해도 잘 안 풀리니까 답답한 거잖아요.","JPN":"理解します。頑張っても上手く行かないから、もどかしいんでしょう？","ENG":"But I understand. You're frustrated because things aren't working out, even when you're trying your best.","TWN":"不過我明白你的心情，拼盡全力卻還是一無所獲，所以很煩躁是吧。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저도 그런 적 많거든요.","JPN":"私もそんな時がたくさんありましたから。","ENG":"I've been in the same situation many times.","TWN":"我也經常那樣。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘도? 항상 웃고 다니는 거 아니었어?","JPN":"ノエルも？　いつも笑ってるんじゃなかったの？","ENG":"You too? I thought you would be smiley-smiley all the time.","TWN":"洛艾兒也是？你不是整天笑呵呵的嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};